import json
import openai

client = openai.OpenAI()  # reads OPENAI_API_KEY from env

# --- Tool definitions (schemas the LLM can call) ---
tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Return current weather for a city.",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {"type": "string", "description": "City name"}
                },
                "required": ["city"],
            },
        },
    }
]

# --- Tool implementations ---
def get_weather(city: str) -> str:
    # Stub; replace with a real weather API call.
    return json.dumps({"city": city, "temperature_c": 22, "condition": "sunny"})

TOOL_MAP = {"get_weather": get_weather}

# --- Agent loop ---
def run_agent(user_message: str, max_steps: int = 10) -> str:
    messages = [
        {"role": "system", "content": "You are a helpful assistant. Use tools when needed."},
        {"role": "user", "content": user_message},
    ]

    for step in range(max_steps):
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=tools,
            tool_choice="auto",
        )
        msg = response.choices[0].message
        messages.append(msg)  # add assistant turn to history

        # No tool calls → model is done
        if not msg.tool_calls:
            return msg.content

        # Execute each requested tool call
        for tc in msg.tool_calls:
            fn_name = tc.function.name
            fn_args = json.loads(tc.function.arguments)
            result = TOOL_MAP[fn_name](**fn_args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": result,
            })

    return "[Agent hit max step limit without completing the task.]"

if __name__ == "__main__":
    answer = run_agent("What is the weather in Paris right now?")
    print(answer)

import json
import anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "lookup_price",
        "description": "Look up the USD price of a product by name.",
        "input_schema": {
            "type": "object",
            "properties": {"product": {"type": "string"}},
            "required": ["product"],
        },
    },
    {
        "name": "convert_currency",
        "description": "Convert an amount from USD to a target currency.",
        "input_schema": {
            "type": "object",
            "properties": {
                "amount_usd": {"type": "number"},
                "target_currency": {"type": "string"},
            },
            "required": ["amount_usd", "target_currency"],
        },
    },
]

def lookup_price(product: str) -> str:
    prices = {"laptop": 1299.00, "headphones": 349.00}
    usd = prices.get(product.lower(), 0)
    return json.dumps({"product": product, "price_usd": usd})

def convert_currency(amount_usd: float, target_currency: str) -> str:
    rates = {"EUR": 0.92, "GBP": 0.79, "JPY": 157.4}
    rate = rates.get(target_currency.upper(), 1.0)
    return json.dumps({"amount": round(amount_usd * rate, 2), "currency": target_currency})

TOOL_MAP = {"lookup_price": lookup_price, "convert_currency": convert_currency}

def run_agent(user_message: str, max_steps: int = 10) -> str:
    messages = [{"role": "user", "content": user_message}]
    for _ in range(max_steps):
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})
        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                fn = TOOL_MAP[block.name]
                result = fn(**block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})
    return "[max steps reached]"

